# Removes all COLDP issue keywords and their associated tags from a project.
#
# ~~ generated by Claude ~~
class BulkColdpIssueCleanupJob < ApplicationJob
  queue_as :coldp_export

  def perform(project_id, user_id)
    Current.user_id = user_id
    Current.project_id = project_id

    Keyword.where(project_id: project_id)
      .where('name LIKE ?', 'COLDP: %')
      .destroy_all
  end
end
